  "mode": "io",
  "tests": [
    {
      "name": "basic_case",
      "input": "1\n2\n3\n",
      "output": "6\n",
      "notes": "Basic test case to verify simple addition."
    },
    {
      "name": "negative_numbers",
      "input": "-1\n-2\n-3\n",
      "output": "-6\n",
      "notes": "Tests handling of negative numbers."
    },
    {
      "name": "zero_case",
      "input": "0\n0\n0\n",
      "output": "0\n",
      "notes": "Edge case with all zeros."
    },
    {
      "name": "large_numbers",
      "input": "1000000\n2000000\n3000000\n",
      "output": "6000000\n",
      "notes": "Tests handling of large integers."
    },
    {
      "name": "mixed_numbers",
      "input": "-1\n2\n-3\n",
      "output": "-2\n",
      "notes": "Tests mixed positive and negative numbers."
    },
    {
      "name": "single_input",
      "input": "5\n",
      "output": "5\n",
      "notes": "Tests the case with a single input number."
    },
    {
      "name": "two_large_numbers",
      "input": "999999999\n888888888\n",
      "output": "1888888887\n",
      "notes": "Tests addition of two very large numbers."
    },
    {
      "name": "all_positive",
      "input": "1\n2\n3\n4\n5\n",
      "output": "15\n",
      "notes": "Tests addition of multiple positive numbers."
    }
  ],
  "assumptions": "Inputs are always integers.",
  "notes": "Ensure to handle both positive and negative integers correctly."
}
